const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'sb_publishable_HsIkelEZaIr0VauiB3GgIQ_59XJRoWc';
const KIEAI_API_KEY = '706600fe6244dedaa3c72b71ffe52e97';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';

// Fetch email config from app_config (centralized source of truth)
let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
if (!recipient_email) {
  try {
    const rows = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value&user_id=eq.${userId}`,
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
    });
    for (const row of rows) {
      if (row.key === 'recipient_email') recipient_email = row.value;
      if (row.key === 'bcc_email') bcc_email = row.value;
    }
  } catch (e) {
    recipient_email = 'eric@agileadtesting.com';
    bcc_email = '';
  }
}

// Genre-specific art guidelines
const genre = trigger.genre_slug || 'post-apocalyptic';
const guidelines = {
  'post-apocalyptic': 'Muted earth tones, atmospheric haze, dramatic lighting. Overgrown ruins, crumbling infrastructure, vast empty landscapes. Mood: haunting beauty in decay. Style: cinematic concept art, digital matte painting.',
  'political-scifi': 'Dark imposing structures, dramatic chiaroscuro lighting. Vast space stations, parliamentary chambers, propaganda aesthetics. Mood: cerebral tension. Style: retro-futurism meets brutalist architecture.',
  'historical-time-travel': 'Rich period-accurate details, warm golden-hour lighting. Layered timelines shown through visual juxtaposition. Mood: nostalgic wonder. Style: romantic realism with subtle anachronisms.',
  'ai-marketing': 'Clean minimalist tech aesthetic, gradient blues and purples. Circuit patterns, neural network visualizations, data streams. Mood: innovative and forward-looking. Style: modern digital art, sleek corporate futurism.',
  'political-history': 'Documentary-style gravitas, amber and sepia tones. Architecture of power, crowds, pivotal moments. Mood: weight of history. Style: oil painting meets photojournalism.',
  'ancient-history': 'Classical painting style, warm golden light, rich earth tones with lapis lazuli and gold accents. Marble, stone, papyrus textures. Mood: reverent immersion. Style: neoclassical oil painting, museum-quality detail.',
  'metaphysical-romance': 'Ethereal soft light, dreamlike atmosphere, warm pastels with deep jewel tones. Mist, glowing auras, intertwined silhouettes. Mood: transcendent longing and soul-deep connection. Style: surrealist romanticism, luminous digital painting.'
};
const art_guidelines = guidelines[genre] || guidelines['post-apocalyptic'];

return [{ json: { art_guidelines, recipient_email, bcc_email: bcc_email || '', KIEAI_API_KEY } }];

const trigger = $('workflow_trigger').first().json;
const settings = $('settings').first().json;

const description = trigger.image_description || '';
const title = trigger.story_title || '';
const genre = trigger.genre_slug || '';
const artGuidelines = settings.art_guidelines || '';

// Build a Midjourney-style prompt optimized for NanoBanana PRO
// Combine the scene description with genre art direction
const prompt = `${description}. ${artGuidelines} Book cover composition, professional quality, highly detailed, 16:9 aspect ratio --ar 16:9 --stylize 750 --v 7`;

return [{ json: { prompt, title, genre } }];
